ent.form.telefone.value = telefone.value + '-';                }            }            function mascaraCel(celular) {                if (celular.value.length == '0') {                    document.form.celular.value = '(' + celular.value;                }                if (celular.value.length == '3') {                    document.form.celular.value = celular.value + ') ';                }                if (celular.value.length == '9') {                    document.form.celular.value = celular.value + '-';                }            }            function mascaraCPF(cpf) {                if (cpf.value.length == '3') {                    document.form.cpf.value = cpf.value + '.';                }                if (cpf.value.length == '7') {                    document.form.cpf.value = cpf.value + '.';                }                if (cpf.value.length == '11') {                    document.form.cpf.value = cpf.value + '-';                }            }            function mascaraData(datNascimento) {                if (datNascimento.value.length == '2') {                    document.form.datNascimento.value = datNascimento.value + '/';                }                if (datNascimento.value.length == '5') {                    document.form.datNascimento.value = datNascimento.value + '/';                }            }            function mascaraCEP(cep) {                if (cep.value.length == '2') {                    document.form.cep.value = cep.value + '.';                }                if (cep.value.length == '6') {                    document.form.cep.value = cep.value + '-';                }            }            function buscaEndereco(CEP) {                if (CEP != "") {                    $('#spanLogradouro').html('<progress></progress>');                    $('#spanLogradouro').load("../AJAX/enderecoPorCEP.php?cep=" + CEP + "&campo=logradouro", "",                            function(responseText, textStatus, XMLHttpRequest) {                                if (textStatus == 'error') {                                    $('#spanLogradouro').html('<font color="red">(Erro de conexão com servidor. Tente novamente)</font>');                                }                            }                    );                    $('#spanBairro').html('<progress></progress>');                    $('#spanBairro').load("../AJAX/enderecoPorCEP.php?cep=" + CEP + "&campo=bairro", "",                            function(responseText, textStatus, XMLHttpRequest) {                                if (textStatus == 'error') {                                    $('#spanBairro').html('<font color="red">(Erro de conexão com servidor. Tente novamente)</font>');                                }                            }                    );                    $('#spanEstado').html('<progress></progress>');                    $('#spanEstado').load("../AJAX/enderecoPorCEP.php?cep=" + CEP + "&campo=uf_sigla", "",                            function(responseText, textStatus, XMLHttpRequest) {                                if (textStatus == 'error') {                                    $('#spanEstado').html('<font color="red">(Erro de conexão com servidor. Tente novamente)</font>');                                }                            }                    );                    $('#spanCidade').html('<progress></progress>');                    $('#spanCidade').load("../AJAX/enderecoPorCEP.php?cep=" + CEP + "&campo=cidade", "",                            function(responseText, textStatus, XMLHttpRequest) {                                if (textStatus == 'error') {                                    $('#spanCidade').html('<font color="red">(Erro de conexão com servidor. Tente novamente)</font>');                                }                            }                    );                    document.getElementById('numero').focus();                }            }            function contOBS(qtCaracteres) {                if (qtCaracteres > 1000) {                    document.getElementById("contOBS").innerHTML = (1000 - qtCaracteres) * (-1) + " caracteres excedidos";                } else {                    document.getElementById("contOBS").innerHTML = 1000 - qtCaracteres + " caracteres restantes";                }            }            function buscaAJAX(busca, idResultado) {                ////busca é o atributo informado para buscaAJAX.php                //idResultado é o id do elemento que receberá a resposta.                $('#' + idResultado).html('<progress></progress>');                $('#' + idResultado).load("../AJAX/verificaCPF.php?campo1=" + busca, "",                        function(responseText, textStatus, XMLHttpRequest) {                            if (textStatus == 'error') {                                $('#' + idResultado).html('<font color="red">(Erro de conexão com servidor. Tente novamente)</font>');                            }                        }                );            }            function validaForm() {                d = document.form;                if (d.cpf.value == "") {                    alert("O campo CPF deve ser preenchido!");                    d.cpf.focus();                    return false;                }                if (document.getElementById("contCPF").value != 0){                    alert("CPF já cadastrado!");                    return false;                }            }            function geraUsuario2(campo) {                var frase = campo.value;                var palavras = frase.split(" ");                tamanho = palavras.length;                var usuario = (palavras[0]);                usuario = usuario.substr(0, 4);                numero = parseInt(Math.random() * 10000);                usuario = usuario + numero;                usuario = usuario.toUpperCase();                document.getElementById('usuario').value = usuario;            }        </script>    </head>    <body>        <div id="menuInterno">            <?php            include '../Includes/MenuPrincipal.php';            ?>        </div>        <div id="topo">            <div id="rodape">            </div>        </div>        <div id="conteudo">            <form id="form" name="form" method="post" action="../FilesOk/cadClienteOK.php" onsubmit=" return validaForm(this);">                <div id="menuInterno">                    <input type="submit" name="btnCadastrar" value="Cadastrar" class="gmailButton"/>                    <input type="button" name="btnVoltar" value="Voltar" onclick="voltar()" class="gmailButton"/>                </div>                <table class="list">                    <tr>                        <td>Nome:</td>                        <td><input name="nome" type="text" id="nome" autofocus onblur="geraUsuario2(this);" /></td>                        <td>Logradouro:</td>                        <td><span id="spanLogradouro"><input name="logradouro" type="text" id="logradouro" /></span></td>                    </tr>                    <tr>                        <td>Número da casa:</td>                        <td><input name="numero" type="text" id="numero" /></td>                        <td>Bairro:</td>                        <td><span id="spanBairro"><input name="bairro" type="text" id="bairro" /></span></td>                    </tr>                    <tr>                        <td>Estado:</td>                        <td>                            <!--<span id="spanEstado"><select name="estado" id="estado" onchange="selecionaCidade();">                                    <option value="">Selecione um Estado</option>                            <?php                            for ($x = 0; $x < $contadorEstado; $x++) {                                $objEstado = $objEstados[$x];                                ?>  