abel for="usuario">Usuário:</label>                            <input type="text" name="usuario" id="usuario" maxlength="10" />                        </td><td>                            <label for="senha">Senha:</label>                            <input type="text" name="senha" id="senha" maxlength="10"                                   value="<?php echo gerar_sequencia(6, true, false, true, false); ?>"                                   />                        </td>                    </tr>                    <tr>                        <td>OBS:</td>                        <td colspan="3">                            <textarea name="obs" id="obs" cols="60" rows="7"  onkeyup="contOBS(this.value.length)"></textarea><span id="contOBS" ></span>                        </td>                    </tr>                </table>            </form>        </div>    </body></html>